+        `Long-term memory:\n${describeLongTermMemory(memory) || "(none)"}`,
+        `Previous events: ${JSON.stringify(events.slice(-6))}`,
+        `Maximum observe-act steps: ${maxSteps}`
+      ].join("\n\n")
+    }
+  ];
