+  const tab = await getTargetTab(tabId);
+  if (intent === "chat") {
+    const observation = await observeTab(tab);
+    const result = await runPageChat({
+      task,
+      observation,
+      memory: enrichConversationMemory(memory, settings, observation.origin),
