+    id: requestId,
+    origin,
+    appName: "Agenticify Sidebar",
+    scopes: debuggerAccessScopes(),
+    reason: "Enable debugger mode for the current active tab.",
+    requestedAutoRun: true,
+    createdAt: new Date().toISOString()
